INSERT INTO `novel_snapshots` VALUES ('183c3c22ae3042fe8b3696294892fcdc','1779093809974-fb843d07',2,'{\"items\": [], \"outline\": [], \"chapters\": [], \"factions\": [], \"categories\": [], \"characters\": [], \"foreshadows\": [], \"timelineEvents\": [], \"outlineStorylines\": [], \"characterRelations\": [], \"characterFactionMemberships\": []}','2026-05-18 08:51:13','2026-05-18 08:51:13'),('417db50ebd9540139d94d4c3218dc7a6','1779632168238-6d6fb4e6',2,'{\"items\": [], \"outline\": [{\"id\": \"1779633181010-470a6e9f\", \"goal\": \"展现主角的荒诞破案与办证循环\", \"level\": \"volume\", \"order\": 1, \"title\": \"日常循环·第一季\", \"twist\": \"\", \"result\": \"\", \"status\": \"todo\", \"novelId\": \"1779632168238-6d6fb4e6\", \"summary\": \"陆沉在小区的鸡毛蒜皮破案日常，永远拿不到许可证。\", \"tension\": 2, \"conflict\": \"\", \"issueIds\": [], \"location\": \"\", \"parentId\": null, \"suspense\": \"\", \"createdAt\": \"2026-05-24T14:33:01.010Z\", \"plotStage\": \"drafted\", \"proseHint\": \"\", \"timeLabel\": \"\", \"updatedAt\": \"2026-05-24T14:33:01.010Z\", \"factionIds\": [], \"characterIds\": [], \"storylineIds\": [], \"emotionalTurn\": \"\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1779633181010-9cb60a98\", \"goal\": \"引入主角和邻居关系，展现破案风格\", \"level\": \"act\", \"order\": 2, \"title\": \"失踪的宠物龟\", \"twist\": \"\", \"result\": \"\", \"status\": \"todo\", \"novelId\": \"1779632168238-6d6fb4e6\", \"summary\": \"王大妈求助找龟，陆沉开始第一单。\", \"tension\": 2, \"conflict\": \"\", \"issueIds\": [], \"location\": \"\", \"parentId\": \"1779633181010-470a6e9f\", \"suspense\": \"\", \"createdAt\": \"2026-05-24T14:33:01.010Z\", \"plotStage\": \"drafted\", \"proseHint\": \"\", \"timeLabel\": \"\", \"updatedAt\": \"2026-05-24T14:33:01.010Z\", \"factionIds\": [], \"characterIds\": [], \"storylineIds\": [], \"emotionalTurn\": \"\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1779633181011-4bf1ac14\", \"goal\": \"让读者了解陆沉的窘境和破案开端\", \"level\": \"chapter\", \"order\": 3, \"title\": \"催租与接单\", \"twist\