elId\": \"1779632168238-6d6fb4e6\", \"createdAt\": \"2026-05-24T14:33:01.007Z\", \"updatedAt\": \"2026-05-24T14:33:01.007Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1779633181006-2926c821\", \"age\": \"\", \"arc\": \"从讨厌陆沉到逐渐容忍，偶尔帮忙\", \"goal\": \"准时收到房租\", \"name\": \"刘阿姨\", \"notes\": \"房东；泼辣、势利、刀子嘴豆腐心；房子被弄坏或租不出去\", \"gender\": \"\", \"secret\": \"年轻时也爱看侦探小说\", \"aliases\": [], \"novelId\": \"1779632168238-6d6fb4e6\", \"createdAt\": \"2026-05-24T14:33:01.006Z\", \"updatedAt\": \"2026-05-24T14:33:01.006Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1779633181006-f4abcd14\", \"age\": \"\", \"arc\": \"从彻底废柴到稍微有点责任感，但本质不变\", \"goal\": \"成为正式侦探，拿到许可证\", \"name\": \"陆沉\", \"notes\": \"主角；油腻、自大、爱说骚话；被房东赶走，永远穷困\", \"gender\": \"\", \"secret\": \"父亲是退休老刑警，但他不想提\", \"aliases\": [], \"novelId\": \"1779632168238-6d6fb4e6\", \"createdAt\": \"2026-05-24T14:33:01.006Z\", \"updatedAt\": \"2026-05-24T14:33:01.006Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}], \"foreshadows\": [], \"timelineEvents\": [], \"outlineStorylines\": [{\"id\": \"1779633181009-c71e1804\", \"name\": \"破案单元\", \"type\": \"main\", \"color\": \"#FFD700\", \"order\": 1, \"novelId\": \"1779632168238-6d6fb4e6\", \"createdAt\": \"2026-05-24T14:33:01.009Z\", \"updatedAt\": \"2026-05-24T14:33:01.009Z\", \"description\": \"每个独立的小案件，陆沉通过胡扯和运气破案。\"}, {\"id\": \"1779633181009-76cae43a\", \"name\": \"办证主线\", \"type\": \"subplot\", \"color\": \"#8B0000\", \"order\": 2, \"novelId\": \"1779632168238-6d6fb4e6\", \"createdAt\": \"2026-05-24T14:33:01.009Z\", \"updatedAt\": \"2026-05-24T14:33:01.009Z\", \"description\": \"陆沉始终拿不到侦探许可证，每次尝试都因嘴贱失败。\"}, {\"id\": \"1779633181009-ee850d7e\", \"name\": \"日常搞笑\", \"type\": \"custom\", \"color\": \"#00CED1\", \"order\": 3, \"novelId\": \"1779632168238-6d6fb4e6\", \"createdAt\": \"2026-05-24T14:33:01.009Z\", \"updatedAt\": \"2026-05-24T14:33:01.009Z\", \"description\": \"陆沉与邻居、民警、助手的互动，充满无厘头笑料。\"}], \"characterRelations\": [], \"characterFactionMemberships\": []}','2026-05-24 14:33:01','2026-05-24 14:33:01'),('53ecd96839404730942e6ce1a5a81830','1780464873043-118fffc5',3,'{\"items\": [], \"outline\": [{\"id\": \"1780505047122-c6077dee\", \"goal\": \"建立主角沈渊的生存困境，展现其性格与隐脉代价，完成古战场副本主线。\", \"level\": \"volume\", \"order\": 1, \"title\": \"古战场的背叛游戏\", \"twist\": \"柳如烟的真实目的并非传承而是星核碎片；散修联盟是北冥剑派布下的饵。\", \"result\": \"沈渊夺得传承并突破境界，但柳如烟携碎片逃走，北冥剑派增援即将到来。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"北冥剑派设计陷害沈渊暴露隐脉，沈渊被迫逃入灵墟境古战场。古战场内机关重重、怨灵横行，北冥剑派追杀队、三伙散修、神秘女商人柳如烟各怀鬼胎。沈渊在算计与背叛中逐步获得传承，每次动用隐脉都付出虚弱代价，最终利用各方矛盾杀出重围，但自身也变得更加冷酷。\", \"tension\": 3, \"conflict\": \"多方势力争夺传承，互相算计；沈渊隐脉的虚弱代价与怨灵侵扰。\", \"issueIds\": [], \"location\": \"灵墟境古战场（外围→中层→核心）\", \"parentId\": null, \"suspense\": \"柳如烟取得星核碎片将引发什么？北冥剑派高层为何如此重视隐脉？\", \"createdAt\": \"2026-06-03T16:44:07.122Z\", \"plotStage\": \"idea\", \"proseHint\": \"环境描写阴暗压抑，战斗描写干脆利落，对话充满试探与机锋。\", \"timeLabel\": \"七日\", \"updatedAt\": \"2026-06-03T16:44:07.122Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\", \"1780505047116-4eb4d099\", \"1780505047117-829282b1\", \"1780505047117-c98f9323\", \"1780505047118-0b12b198\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047120-95b0326a\", \"1780505047120-0ea65fed\", \"1780505047120-bd36687a\", \"1780505047121-8c56c83b\"], \"emotionalTurn\": \"从被迫逃亡到主动布局，人性逐渐冷酷\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780505047124-943fa032\", \"goal\": \"引出主角处境与隐脉的设定；制造紧迫感逼迫主角进入险境。\", \"level\": \"chapter\", \"order\": 2, \"title\": \"隐脉暴露\", \"twist\": \"沈渊发现隐脉竟可吞噬他人的灵力，但他也立刻感到虚弱。\", \"result\": \"沈渊跳入古战场裂隙，玄冥下令封锁出口。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"沈渊在坊市被北冥剑派设局，比武中被迫显露隐脉异象，被诬陷为邪修。他负伤逃入城郊的灵墟境古战场入口，玄冥率七人追杀队紧随其后。\", \"tension\": 4, \"conflict\": \"北冥剑派设下的陷阱与沈渊的临时应对。\", \"issueIds\": [], \"location\": \"天璇星陆·北冥坊市\", \"parentId\": \"1780505047122-c6077dee\", \"suspense\": \"古战场内有什么？隐脉的代价究竟有多严重？\", \"createdAt\": \"2026-06-03T16:44:07.124Z\", \"plotStage\": \"idea\", \"proseHint\": \"开篇用短句营造紧张感，打斗快速描写，重点表现沈渊的果断与隐脉的邪异。\", \"timeLabel\": \"黄昏\", \"updatedAt\": \"2026-06-03T16:44:07.124Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\", \"1780505047117-829282b1\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047120-95b0326a\", \"1780505047121-8c56c83b\"], \"emotionalTurn\": \"从隐忍到爆发，惊慌但果断\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780505047125-67b3ce3c\", \"goal\": \"展现古战场环境；揭示隐脉代价；引入次要角色老鬼。\", \"level\": \"chapter\", \"order\": 3, \"title\": \"断壁中的第一顿餐\", \"twist\": \"老鬼认出沈渊是北冥剑派通缉者，却主动提出合作，称知道一条密道可抵达中层。\", \"result\": \"两人暂时联手，但互相提防。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"沈渊在古战场外围找到一处废弃祭坛，布下临时阵法休息。他发现自己每动用三次隐脉就会虚弱一天，且虚弱时会出现怨灵幻影。他尝试收集周边资源，遇到第一个散修——盗墓者老鬼。\", \"tension\": 3, \"conflict\": \"沈渊与老鬼因一株灵草发生冲突，沈渊靠隐脉突袭压制老鬼，但付出虚弱一次。\", \"issueIds\": [], \"location\": \"古战场外围·废弃祭坛\", \"parentId\": \"1780505047122-c6077dee\", \"suspense\": \"老鬼是否可信？密道通向何处？\", \"createdAt\": \"2026-06-03T16:44:07.125Z\", \"plotStage\": \"idea\", \"proseHint\": \"描写祭坛的残破与阴森，凸显资源匮乏，对话试探性极强。\", \"timeLabel\": \"第一日\", \"updatedAt\": \"2026-06-03T16:44:07.125Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\", \"1780505047117-c98f9323\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047120-0ea65fed\", \"1780505047121-8c56c83b\"], \"emotionalTurn\": \"从谨慎到试探，逐渐冷酷\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780505047127-ea3ac7b4\", \"goal\": \"引入联盟势力；展现方寒的算计；沈渊开始布局。\", \"level\": \"chapter\", \"order\": 4, \"title\": \"散修联盟的邀请\", \"twist\": \"沈渊利用隐脉感知到其中两人灵力带有北冥剑派功法痕迹，但他不揭穿。\", \"result\": \"沈渊假意加入联盟，并暗中与柳如烟（女商人）传讯（柳如烟尚未现身）。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"沈渊与老鬼沿密道进入中层，遭遇一群怨灵。战斗引来另一伙散修，头目方寒出手相助。方寒邀请沈渊加入他的联盟，声称将共同探索核心区域。沈渊发现联盟中另有两人是北冥剑派的暗探。\", \"tension\": 3, \"conflict\": \"沈渊在联盟中需隐藏身份，同时识别内奸。\", \"issueIds\": [], \"location\": \"古战场中层·碎石甬道\", \"parentId\": \"1780505047122-c6077dee\", \"suspense\": \"北冥剑派的暗探将如何行动？柳如烟何时入场？\", \"createdAt\": \"2026-06-03T16:44:07.127Z\", \"plotStage\": \"idea\", \"proseHint\": \"群戏描写，突出各方神色与微动作，营造暗流涌动感。\", \"timeLabel\": \"第二日\", \"updatedAt\": \"2026-06-03T16:44:07.127Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\", \"1780505047117-c98f9323\", \"1780505047118-0b12b198\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047120-0ea65fed\", \"1780505047120-95b0326a\"], \"emotionalTurn\": \"从怀疑到伪装，内心冷笑\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780505047129-e53c0943\", \"goal\": \"引入柳如烟及其目的；加深各方算计。\", \"level\": \"chapter\", \"order\": 5, \"title\": \"女商人的棋局\", \"twist\": \"柳如烟透露古玉符关乎星核碎片，但沈渊注意到她提及碎片时眼中闪过贪婪，判断她另有图谋。\", \"result\": \"两人达成临时契约，但各自保留关键信息。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"柳如烟以商人身份现身，声称有核心区机关地图，愿与沈渊私下交易，要求他助她取得古玉符。沈渊发现地图有假，但仍将计就计。同时，北冥剑派追杀队在外围集结，玄冥开始内部渗透。\", \"tension\": 3, \"conflict\": \"沈渊与柳如烟的谈判，互相试探底线。\", \"issueIds\": [], \"location\": \"古战场中层·隐蔽石室\", \"parentId\": \"1780505047122-c6077dee\", \"suspense\": \"古玉符与星核碎片的真正作用是什么？\", \"createdAt\": \"2026-06-03T16:44:07.129Z\", \"plotStage\": \"idea\", \"proseHint\": \"对话紧凑，每句话都藏钩子，环境幽暗压抑。\", \"timeLabel\": \"第三日\", \"updatedAt\": \"2026-06-03T16:44:07.129Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\", \"1780505047116-4eb4d099\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047120-bd36687a\"], \"emotionalTurn\": \"从诱惑到清醒，冷静算计\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780505047131-9bed3f4a\", \"goal\": \"强化隐脉代价的严重性；揭露北冥剑派的布局。\", \"level\": \"chapter\", \"order\": 6, \"title\": \"虚弱的代价\", \"twist\": \"沈渊在怨灵袭击中意外吸收了一丝怨气，发现隐脉也能吞噬魂力。\", \"result\": \"沈渊虚弱但未昏迷，并掌握了敌人的阴谋。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"沈渊在探索中被迫连续使用两次隐脉，陷入虚弱期。怨灵实体化袭击，他独自困在石室中，靠布阵硬撑一夜。期间他听到北冥剑派暗探与玄冥的传音对话，得知方寒联盟实为诱饵。\", \"tension\": 4, \"conflict\": \"沈渊与怨灵的战斗，以及对抗虚弱带来的绝望。\", \"issueIds\": [], \"location\": \"古战场中层·封闭石室\", \"parentId\": \"1780505047122-c6077dee\", \"suspense\": \"隐脉吞噬魂力会带来什么后果？玄冥的下一步计划是什么？\", \"createdAt\": \"2026-06-03T16:44:07.131Z\", \"plotStage\": \"idea\", \"proseHint\": \"大量心理描写与环境渲染，突出孤独与压迫感。\", \"timeLabel\": \"第四日夜\", \"updatedAt\": \"2026-06-03T16:44:07.131Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047121-8c56c83b\", \"1780505047120-95b0326a\"], \"emotionalTurn\": \"从绝望到发现新力量，更添阴沉\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780505047133-fc5dd385\", \"goal\": \"利用矛盾，推动剧情；沈渊获得核心区信息。\", \"level\": \"chapter\", \"order\": 7, \"title\": \"联盟的裂痕\", \"twist\": \"老鬼透露核心区藏有灵墟遗骨，但需要血脉钥匙才能激活。沈渊联想到自己的隐脉可能正是钥匙。\", \"result\": \"沈渊获得灵墟遗骨信息，同时削弱了联盟与北冥剑派。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"沈渊回到散修联盟，故意透露假消息引动内奸。方寒发现两名北冥剑派暗探，与其冲突，联盟分裂。老鬼趁乱偷取机关图，被沈渊当场抓获，沈渊借机立威并逼老鬼说出更多情报。\", \"tension\": 4, \"conflict\": \"联盟内乱，沈渊以雷霆手段控制老鬼。\", \"issueIds\": [], \"location\": \"古战场中层·临时营地\", \"parentId\": \"1780505047122-c6077dee\", \"suspense\": \"灵墟遗骨与沈渊家族有何关联？\", \"createdAt\": \"2026-06-03T16:44:07.133Z\", \"plotStage\": \"idea\", \"proseHint\": \"动作场面利落，对话充满威胁与算计。\", \"timeLabel\": \"第五日\", \"updatedAt\": \"2026-06-03T16:44:07.133Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\", \"1780505047117-c98f9323\", \"1780505047118-0b12b198\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047120-0ea65fed\", \"1780505047120-95b0326a\"], \"emotionalTurn\": \"从隐匿到主动出击，掌控局势\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780505047135-85624845\", \"goal\": \"柳如烟的背叛；沈渊面临绝境。\", \"level\": \"chapter\", \"order\": 8, \"title\": \"核心禁地的陷阱\", \"twist\": \"傀儡死后，核心区出现一个传送阵，灵墟遗骨就藏在阵后，但需要沈渊的血脉才能打开。\", \"result\": \"沈渊虚弱倒地，柳如烟逃离，其他散修试图杀死沈渊，北冥剑派追杀队适时赶到。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"沈渊、柳如烟、老鬼及残余散修进入核心区。机关重重，柳如烟利用古玉符破解部分禁制，但触发了一个守护傀儡（太渊境）。战斗中沈渊三次动用隐脉击杀傀儡，随即陷入虚弱，柳如烟突然翻脸，夺走古玉符并抛下沈渊。\", \"tension\": 5, \"conflict\": \"对抗傀儡与柳如烟的背叛。\", \"issueIds\": [], \"location\": \"古战场核心·祭坛前\", \"parentId\": \"1780505047122-c6077dee\", \"suspense\": \"沈渊如何应对三重杀局？\", \"createdAt\": \"2026-06-03T16:44:07.135Z\", \"plotStage\": \"idea\", \"proseHint\": \"场面混乱，打斗惨烈，突出沈渊的孤立与隐忍。\", \"timeLabel\": \"第六日\", \"updatedAt\": \"2026-06-03T16:44:07.135Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\", \"1780505047116-4eb4d099\", \"1780505047117-829282b1\", \"1780505047117-c98f9323\", \"1780505047118-0b12b198\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047120-bd36687a\", \"1780505047120-95b0326a\", \"1780505047120-0ea65fed\"], \"emotionalTurn\": \"从合作到被背叛，愤怒但冷静\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780505047137-6a76ca4b\", \"goal\": \"沈渊进入真正传承之地；与玄冥最终对决前奏。\", \"level\": \"chapter\", \"order\": 9, \"title\": \"血脉之门\", \"twist\": \"传送阵开启后不仅传走了沈渊，还触发了古战场的自毁机关（三天后崩塌）。\", \"result\": \"沈渊被传送到核心密室，玄冥无法进入，但封锁了密室周围。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"玄冥率队包围沈渊，要求他开启传送阵。沈渊拖延时间，暗中恢复。老鬼和方寒见势不妙逃离。沈渊利用隐脉吞吸了周围怨灵之力，强行恢复部分体力，以血开门，传送阵启动。玄冥追击，沈渊踏入传送阵。\", \"tension\": 4, \"conflict\": \"沈渊与玄冥的短暂交手，并利用传送阵逃离。\", \"issueIds\": [], \"location\": \"古战场核心·传送阵前\", \"parentId\": \"1780505047122-c6077dee\", \"suspense\": \"密室中有什么？自毁倒计时下各势力如何反应？\", \"createdAt\": \"2026-06-03T16:44:07.137Z\", \"plotStage\": \"idea\", \"proseHint\": \"紧凑的逃亡与对峙，环境细节突出危险。\", \"timeLabel\": \"第七日晨\", \"updatedAt\": \"2026-06-03T16:44:07.137Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\", \"1780505047117-829282b1\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047120-95b0326a\", \"1780505047121-8c56c83b\"], \"emotionalTurn\": \"从危机到搏命，决绝\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780505047139-73a58b1c\", \"goal\": \"主角获得关键成长与信息；推动高潮。\", \"level\": \"chapter\", \"order\": 10, \"title\": \"遗骨与真相\", \"twist\": \"沈渊发现星核碎片正是柳如烟的目标，而且碎片能感应到其他碎片的位置。\", \"result\": \"沈渊融合遗骨，境界突破，但密室开始坍塌。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"密室中有一具晶莹骸骨（灵墟遗骨）和一块星核碎片。沈渊接触到骸骨时，隐脉共鸣，他脑海中闪过家族被灭门的片段，得知自己是上古隐脉家族的后裔。遗骨中残留的传承让他修为突破至神道境（打通三个新穴位）。但同时也触动了古战场自毁加速。\", \"tension\": 4, \"conflict\": \"消化传承与逃离自毁的时间赛跑。\", \"issueIds\": [], \"location\": \"古战场核心·密室\", \"parentId\": \"1780505047122-c6077dee\", \"suspense\": \"沈渊如何逃出？柳如烟和玄冥会否相遇？\", \"createdAt\": \"2026-06-03T16:44:07.139Z\", \"plotStage\": \"idea\", \"proseHint\": \"氛围神秘而悲壮，回忆插叙简洁有力。\", \"timeLabel\": \"第七日午\", \"updatedAt\": \"2026-06-03T16:44:07.139Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047121-8c56c83b\"], \"emotionalTurn\": \"从震惊到明悟，仇恨与野心交织\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780505047140-59b4f921\", \"goal\": \"解决第一卷主要冲突，留下续集钩子。\", \"level\": \"chapter\", \"order\": 11, \"title\": \"最后的突围\", \"twist\": \"玄冥临死前告知沈渊，北冥剑派早已知道他家族秘密，这次追杀只是试探；柳如烟的星核碎片只是冰山一角。\", \"result\": \"沈渊成功突围，但暴露了身份；柳如烟带碎片不知所踪。\", \"status\": \"todo\", \"novelId\": \"1780464873043-118fffc5\", \"summary\": \"沈渊冲出密室，发现玄冥、柳如烟、方寒等人正混战。他利用新获得的力量和机关，先后设计杀死玄冥、方寒和老鬼。柳如烟趁乱抢走星核碎片逃出古战场。沈渊没有追击，而是毁掉出口，将北冥剑派增援挡在门外。古战场崩塌前，他带着部分传承物资从另一条密道离开。\", \"tension\": 5, \"conflict\": \"多方混战，沈渊的复仇与算计。\", \"issueIds\": [], \"location\": \"古战场核心至外围\", \"parentId\": \"1780505047122-c6077dee\", \"suspense\": \"北冥剑派下一步行动？柳如烟背后的势力？星核碎片隐藏的秘密？\", \"createdAt\": \"2026-06-03T16:44:07.140Z\", \"plotStage\": \"idea\", \"proseHint\": \"战斗场面宏大但节奏快，突出沈渊的冷酷与果断。\", \"timeLabel\": \"第七日黄昏\", \"updatedAt\": \"2026-06-03T16:44:07.140Z\", \"factionIds\": [], \"characterIds\": [\"1780505047114-107cb3f2\", \"1780505047117-829282b1\", \"1780505047116-4eb4d099\", \"1780505047117-c98f9323\", \"1780505047118-0b12b198\"], \"storylineIds\": [\"1780505047120-84812548\", \"1780505047120-95b0326a\", \"1780505047120-0ea65fed\", \"1780505047120-bd36687a\"], \"emotionalTurn\": \"从激战到冷漠，完成蜕变\", \"foreshadowIds\": [], \"povCharacterId\": null}], \"chapters\": [], \"factions\": [], \"categories\": [], \"characters\": [{\"id\": \"1780505047118-0b12b198\", \"age\": \"\", \"arc\": \"从临时联盟盟主，到暴露两面派面目，被沈渊设计击败。\", \"goal\": \"夺取古战场中的“灵墟遗骨”作为冲击神道境的契机。\", \"name\": \"散修头目方寒\", \"notes\": \"配角；沉稳冷静，善于分析，偶尔流露野心。；表面温和有礼，实则腹黑，善于团结散修形成联盟。；联盟内部不牢，被北冥剑派或沈渊渔翁得利。\", \"gender\": \"\", \"secret\": \"他隐藏了真实修为（实为太渊境巅峰），并私下与北冥剑派某人有联系。\", \"aliases\": [], \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.118Z\", \"updatedAt\": \"2026-06-03T16:44:07.118Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1780505047117-c98f9323\", \"age\": \"\", \"arc\": \"最初想黑吃黑，后与沈渊暂时联盟，最终背叛被反杀。\", \"goal\": \"在古战场捞够宝物，换取资源突破境界。\", \"name\": \"盗墓者老鬼\", \"notes\": \"配角；沙哑粗粝，说话带江湖黑话。；贪婪狡猾，见风使舵，但有一定底限。；被强大势力灭口或死于机关怨灵。\", \"gender\": \"\", \"secret\": \"他曾是某个小宗门的叛徒，身上带着宗门禁地地图（关联古战场深处）。\", \"aliases\": [], \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.117Z\", \"updatedAt\": \"2026-06-03T16:44:07.117Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1780505047117-829282b1\", \"age\": \"\", \"arc\": \"从志在必得的追猎者，到被沈渊逐步瓦解优势，最终战败陨落。\", \"goal\": \"完成派内任务，活捉沈渊并夺取隐脉秘密。\", \"name\": \"玄冥\", \"notes\": \"对手；冰冷威严，命令式口吻，不容质疑。；骄傲自负，但对北冥剑派忠诚，心思缜密。；任务失败影响自己在门派中的地位，被同僚取代。\", \"gender\": \"\", \"secret\": \"他其实暗中修炼了禁术，以提升修为，导致体内隐有暗伤。\", \"aliases\": [], \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.117Z\", \"updatedAt\": \"2026-06-03T16:44:07.117Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1780505047116-4eb4d099\", \"age\": \"\", \"arc\": \"从算计主角到被主角反算计，最终可能成为盟友或敌人。\", \"goal\": \"夺取古战场中的一件特殊法器（古玉符），用于解开某处禁制。\", \"name\": \"柳如烟\", \"notes\": \"盟友（伪）；语调妩媚，话中有话，常以利益诱惑。；精明市侩，善于伪装，为达目的不择手段。；被北冥剑派或沈渊识破真正意图，功亏一篑。\", \"gender\": \"\", \"secret\": \"她与北冥剑派有私仇，但更觊觎古战场中隐藏的“星核碎片”，古玉符只是寻找碎片的钥匙。\", \"aliases\": [], \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.116Z\", \"updatedAt\": \"2026-06-03T16:44:07.116Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1780505047114-107cb3f2\", \"age\": \"\", \"arc\": \"从被迫逃亡的猎物，逐渐成长为主动布局的猎手，但代价是人性逐渐冷酷。\", \"goal\": \"追求自由，打破星陆秩序，摆脱被操控的命运。\", \"name\": \"沈渊\", \"notes\": \"主角；语气阴沉，话语简短，常带讥讽与试探。；谨慎多疑，狠辣无情，欺软怕硬，老谋深算。；再次沦为他人工具，被囚禁或控制失去自主。\", \"gender\": \"\", \"secret\": \"真实身份是隐世家族遗孤，隐脉为家族血脉特征，但自己尚不完全知晓。\", \"aliases\": [], \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.114Z\", \"updatedAt\": \"2026-06-03T16:44:07.114Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}], \"foreshadows\": [], \"worldSettings\": [{\"id\": \"1780466950196-4f65c629\", \"name\": \"《怪杀》修仙世界：穴位境界与多星势力纷争\", \"content\": \"【力量体系】修炼境界以人体穴位为根基，共分十二正经与奇经八脉二十阶，每阶对应一个穴位，境界名源于《黄帝内经》与古代星象典故，如“太渊境”“神道境”“灵墟境”等。修炼者需打通穴位并引天地灵气淬炼，但存在天赋异禀者能突破常规，创出“隐脉”或“变异窍穴”，从而超越既定境界体系。典型成长路径：引气入体→冲脉（打通第一个穴位）→周天循环→每通一穴升一阶，直至任督贯通后进入“天人合一”的隐藏领域。【世界结构】世界为单一凡界，但悬浮着数十颗“星陆”，每颗星陆大小如大陆，被巨树或灵脉连接。人类主宰多数星陆，妖魔隐匿于荒芜星陆或地下裂隙。星陆间分布势力，每个星陆内又有多个宗派、王朝或家族割据，例如中央星陆有正道七宗与魔门三教，边缘星陆则存在古妖巢穴或秘境遗迹。【社会规则】凡间王朝与修仙宗门并存，凡人供奉宗门以求庇护，宗门不得干预世俗皇权更迭，但暗中操控资源。猎杀妖魔需向官方申领“诛魔令”，但实际多为宗门内斗或铲除异己的借口。存在“灵脉税”与“星陆通行税”，跨星陆贸易由大型商会垄断。【历史脉络】上古时期，天地灵气充沛，妖魔横行，人族先贤从星辰运行与人体奥秘中悟出穴位修炼法，建立初始秩序。千年前“破壁之战”中，有修士强行融合妖丹与穴位，引发空间震荡，部分星陆碎片化为秘境。此后正道与魔道互指为“怪”，杀戮不止，仇恨代代累积。【核心设定】书名《怪杀》并非指杀怪物，而是讽刺世人将异己者视为“怪”并互相残杀。修仙者之间因理念、资源、历史的矛盾，比对抗真妖魔更加惨烈。每个势力都坚信自己代表正义，对手是必须铲除的“怪”。力量体系中“超脱体系”者往往被视为异端或怪物，招致围攻，但历史证明他们才是突破时代局限的先驱。\", \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T06:09:10.196Z\", \"updatedAt\": \"2026-06-03T13:41:23.768Z\", \"attributes\": [{\"id\": \"1780494083768-22d562f5\", \"key\": \"力量体系总纲\", \"value\": \"修炼以人体穴位为根基，共二十阶，对应十二正经与奇经八脉。境界名源于《黄帝内经》与星象典故。成长路径：引气入体→冲脉（打通首穴）→周天循环→每通一穴升一阶→任督贯通后进入「天人合一」隐藏领域。每升一阶，灵气储量、五感、寿元、体魄皆质变。一境之差，便是蝼蚁与猛兽的距离。\"}, {\"id\": \"1780494083768-9f90fba3\", \"key\": \"二十阶境界详表\", \"value\": \"十二正经（十二阶）：太渊境（手太阴）、商阳境（手阳明）、厉兑境（足阳明）、隐白境（足太阴）、少冲境（手少阴）、少泽境（手太阳）、至阴境（足太阳）、涌泉境（足少阴）、大陵境（手厥阴）、关冲境（手少阳）、窍阴境（足少阳）、大敦境（足厥阴）。奇经八脉（八阶）：长强境（督脉）、会阴境（任脉）、冲脉境、带脉境、阳跷境、阴跷境、阳维境、阴维境。再往上便是无可名状的「天人合一」——传闻无人真正到过。\"}, {\"id\": \"1780494083768-be25f382\", \"key\": \"隐脉与变异窍穴\", \"value\": \"天地有漏，规则有缝。极少数天才能在冲脉时触发出「隐脉」——不存在于任何医典中的隐藏经脉，或在已通穴位上产生「变异窍穴」，获得超规格的神通。隐脉开一条，等同多修一个体系；变异窍穴则可让同一境界碾压同阶。但代价极大：经脉冲突时生不如死，走火入魔只在瞬息之间。敢走这条路的人，不是疯子就是注定登顶的人。\"}, {\"id\": \"1780494083768-8fafc4dd\", \"key\": \"三大星域\", \"value\": \"数十颗星陆悬浮于凡界之上，按灵气浓度划分为三大星域。内域：七颗主星陆环绕中央天柱，灵气如雾凝露，是七大天宗的根基所在，弱者踏上去都会被灵气撑爆经脉。中域：二十余颗星陆散布环绕，灵气充沛但分布不均，中型宗门与王朝割据，是大多数修士毕生活跃的舞台。外域：边缘破碎星陆与蛮荒星体，灵气稀薄但秘境、古妖巢穴、上古遗迹众多，亡命徒、猎宝者、被追杀者的避风港。星陆间以传送法阵、灵脉飞舟、通天巨树往来——当然，没钱就只能靠肉身横渡虚空，九死一生。\"}, {\"id\": \"1780494083768-8ebf5744\", \"key\": \"七大天宗（内域格局）\", \"value\": \"内域七颗主星陆各踞一宗，无所谓正邪，只有利益与实力。太虚宗——擅阵法与虚空之术，情报网遍布星域；玄黄宗——炼体与炼器称霸，肉身即法宝；星辰阁——推演天机、占卜星象，最神秘的势力；血河殿——以血炼道，吞噬他人修为化为己用，手段最残忍；万剑山——一剑破万法，剑修圣地，傲慢且排外；天机谷——傀儡术与机关术登峰造极，以量取胜；长生门——精丹药与医道，掌控疗伤延寿命脉，谁都欠他们人情。七宗之间时有合纵连横，但没有人信盟友——因为这世界唯一不变的法则就是往上爬。\"}, {\"id\": \"1780494083768-d02311a0\", \"key\": \"攀登者法则\", \"value\": \"这个世界没有善恶，只有强弱。每个人都是为了向更高处攀登——资源有限、星陆有层、境界有阶，想上去就必须把别人踩下去。杀伐果断不是性格，是生存的本能。师徒关系是投资与回报的契约，同门是暂时的队友也是未来的对手，道侣可以因一枚丹药反目。弱者依附强者，强者觊觎更高者的位置。修仙界就是一座垂直的角斗场——要么爬上去，要么变成别人脚下的骸骨。\"}, {\"id\": \"1780494083768-8030e781\", \"key\": \"诛魔令与猎杀法则\", \"value\": \"妖魔并非邪恶，而是灵气争夺中的另一条进化路径：妖兽开智、厉鬼聚灵、异物化形，都在和修士抢资源。「诛魔令」是合法的资源猎取执照，分天地玄黄四等，持令可猎杀对应等级的妖魔获取妖丹、精魄、灵材。但荒外星陆上没有执法者——猎魔队反被劫杀、夺令灭口是家常便饭。诛魔令的另一面，是杀人令。\"}, {\"id\": \"1780494083768-8df62443\", \"key\": \"世俗与宗门的共生\", \"value\": \"凡间王朝供奉灵石与香火给宗门，宗门为王朝提供武力威慑与庇佑。表面互不干涉皇权，实则宗门通过「外盟会」渗透朝堂。但七宗互相制衡，谁也不敢明目张胆吞并世俗——「星陆公约」是最后一道保险，触犯者遭群起围攻。世俗权贵也精得很，常借宗门内斗左右逢源、保全己身。底层凡人则是最沉默的基石——他们供养着整个修仙世界的运转，却一辈子也修不到太渊境。\"}], \"categoryIds\": []}], \"timelineEvents\": [], \"outlineStorylines\": [{\"id\": \"1780505047120-84812548\", \"name\": \"主线\", \"type\": \"main\", \"color\": \"#c0392b\", \"order\": 1, \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.120Z\", \"updatedAt\": \"2026-06-03T16:44:07.120Z\", \"description\": \"沈渊在古战场中求生、夺取传承并反击追杀。\"}, {\"id\": \"1780505047120-95b0326a\", \"name\": \"北冥追杀\", \"type\": \"antagonist\", \"color\": \"#2c3e50\", \"order\": 2, \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.120Z\", \"updatedAt\": \"2026-06-03T16:44:07.120Z\", \"description\": \"北冥剑派追杀队设局围剿沈渊，同时暗中觊觎古战场宝藏。\"}, {\"id\": \"1780505047120-0ea65fed\", \"name\": \"散修博弈\", \"type\": \"subplot\", \"color\": \"#f39c12\", \"order\": 3, \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.120Z\", \"updatedAt\": \"2026-06-03T16:44:07.120Z\", \"description\": \"三伙散修为争夺传承相互算计，与沈渊形成复杂联盟。\"}, {\"id\": \"1780505047120-bd36687a\", \"name\": \"女商暗棋\", \"type\": \"character\", \"color\": \"#8e44ad\", \"order\": 4, \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.120Z\", \"updatedAt\": \"2026-06-03T16:44:07.120Z\", \"description\": \"神秘女商人柳如烟接近沈渊，表面合作实则另有目的。\"}, {\"id\": \"1780505047121-8c56c83b\", \"name\": \"隐脉觉醒\", \"type\": \"world\", \"color\": \"#27ae60\", \"order\": 5, \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.120Z\", \"updatedAt\": \"2026-06-03T16:44:07.120Z\", \"description\": \"沈渊逐渐掌握隐脉力量，但付出虚弱代价，并受怨灵侵扰。\"}], \"characterRelations\": [{\"id\": \"1780505047119-afadf4fa\", \"note\": \"柳如烟与北冥剑派有旧怨，玄冥亦知她身份，欲除之而后快。；互不相让，柳如烟利用沈渊牵制玄冥，玄冥则想一网打尽。；互不相让，柳如烟利用沈渊牵制玄冥，玄冥则想一网打尽。\", \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.119Z\", \"updatedAt\": \"2026-06-03T16:44:07.119Z\", \"relationType\": \"敌对\", \"toCharacterId\": \"1780505047117-829282b1\", \"fromCharacterId\": \"1780505047116-4eb4d099\"}, {\"id\": \"1780505047119-655a7c97\", \"note\": \"方寒表面拉拢沈渊加入联盟，实则想拿他当探路石。；虚与委蛇，暗中拆台，最终在传承争夺中正面冲突。；虚与委蛇，暗中拆台，最终在传承争夺中正面冲突。\", \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.119Z\", \"updatedAt\": \"2026-06-03T16:44:07.119Z\", \"relationType\": \"竞争\", \"toCharacterId\": \"1780505047118-0b12b198\", \"fromCharacterId\": \"1780505047114-107cb3f2\"}, {\"id\": \"1780505047119-3b19361e\", \"note\": \"老鬼想黑吃黑，被沈渊反制后暂时屈服，但一直寻找机会报复。；从敌对到临时联盟，老鬼最后背叛，被沈渊斩杀。；从敌对到临时联盟，老鬼最后背叛，被沈渊斩杀。\", \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.119Z\", \"updatedAt\": \"2026-06-03T16:44:07.119Z\", \"relationType\": \"竞争\", \"toCharacterId\": \"1780505047117-c98f9323\", \"fromCharacterId\": \"1780505047114-107cb3f2\"}, {\"id\": \"1780505047119-2194aeed\", \"note\": \"北冥剑派追杀队队长，奉命活捉沈渊，视其为任务目标。；多次交手，玄冥逐渐发现沈渊隐脉的威胁，从轻视到不惜代价围剿。；多次交手，玄冥逐渐发现沈渊隐脉的威胁，从轻视到不惜代价围剿。\", \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.119Z\", \"updatedAt\": \"2026-06-03T16:44:07.119Z\", \"relationType\": \"敌对\", \"toCharacterId\": \"1780505047117-829282b1\", \"fromCharacterId\": \"1780505047114-107cb3f2\"}, {\"id\": \"1780505047118-d745573d\", \"note\": \"互相利用，各怀鬼胎，表面合作寻找传承，实则都觊觎对方掌握的信息。；从合作到互相算计，最终可能因共同对抗北冥剑派而短暂结盟，但随时会翻脸。；从合作到互相算计，最终可能因共同对抗北冥剑派而短暂结盟，但随时会翻脸。\", \"novelId\": \"1780464873043-118fffc5\", \"createdAt\": \"2026-06-03T16:44:07.118Z\", \"updatedAt\": \"2026-06-03T16:44:07.118Z\", \"relationType\": \"竞争\", \"toCharacterId\": \"1780505047116-4eb4d099\", \"fromCharacterId\": \"1780505047114-107cb3f2\"}], \"characterFactionMemberships\": []}','2026-06-03 13:23:17','2026-06-03 16:44:07'),('55ef0a7ec56649f38c0ee22d84cc971e','1780052393947-a77672e0',3,'{\"items\": [], \"outline\": [{\"id\": \"1780290346044-d19a9d66\", \"goal\": \"展现苏敛的权谋手段和世界规则，建立核心冲突和势力格局。\", \"level\": \"volume\", \"order\": 1, \"title\": \"诸界棋局\", \"twist\": \"\", \"result\": \"\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"第一卷：凡心入局。苏敛在边境小镇开设万事阁，以情报交易为起点，布下覆盖三族的巨大棋局。\", \"tension\": 3, \"conflict\": \"\", \"issueIds\": [], \"location\": \"\", \"parentId\": null, \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.044Z\", \"plotStage\": \"idea\", \"proseHint\": \"\", \"timeLabel\": \"\", \"updatedAt\": \"2026-06-01T05:05:46.044Z\", \"factionIds\": [], \"characterIds\": [], \"storylineIds\": [\"1780290346042-16e4f667\", \"1780290346043-53fa3dfa\"], \"emotionalTurn\": \"\", \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1780290346046-fecb8089\", \"goal\": \"初步建立万事阁的声名，获得第一笔资源，并收服第一个重要棋子厉寒。\", \"level\": \"act\", \"order\": 2, \"title\": \"挑拨渔利\", \"twist\": \"\", \"result\": \"\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"苏敛利用伪造的灵药情报，挑拨仙魔两派内斗，从中渔利，并使魔宗少主厉寒成为死士。\", \"tension\": 2, \"conflict\": \"\", \"issueIds\": [], \"location\": \"边境小镇，万事阁\", \"parentId\": \"1780290346044-d19a9d66\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.046Z\", \"plotStage\": \"idea\", \"proseHint\": \"开篇以日常买卖的闲适氛围切入，逐渐透露各方势力的暗流。\", \"timeLabel\": \"初春\", \"updatedAt\": \"2026-06-01T05:05:46.046Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346040-9c0782a6\"], \"storylineIds\": [\"1780290346042-16e4f667\"], \"emotionalTurn\": \"\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346047-ff511a63\", \"goal\": \"让读者了解万事阁的运作和苏敛的伪装能力。\", \"level\": \"chapter\", \"order\": 3, \"title\": \"开张与试探\", \"twist\": \"\", \"result\": \"读者意识到苏敛表面无害实则心机深沉，并期待后续发展。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"万事阁开业，苏敛同时接待仙魔两派的探子，借机散布假情报。\", \"tension\": 3, \"conflict\": \"\", \"issueIds\": [], \"location\": \"万事阁\", \"parentId\": \"1780290346046-fecb8089\", \"suspense\": \"假情报是否能成功骗过双方？\", \"createdAt\": \"2026-06-01T05:05:46.047Z\", \"plotStage\": \"idea\", \"proseHint\": \"描写精致的茶具、看似随意的对话，通过细节暗示信息的真假。\", \"timeLabel\": \"白天\", \"updatedAt\": \"2026-06-01T05:05:46.047Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346040-9c0782a6\"], \"storylineIds\": [\"1780290346042-16e4f667\"], \"emotionalTurn\": \"从平淡到暗藏锋芒\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346048-23e49bbc\", \"goal\": \"展示苏敛的圆滑和信息操控能力。\", \"level\": \"scene\", \"order\": 4, \"title\": \"仙魔来访\", \"twist\": \"\", \"result\": \"双方都相信了苏敛的话，决定采取行动。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"仙族探子云华和魔族使者先后抵达万事阁，苏敛分别接待，透露同一份情报的不同版本。\", \"tension\": 3, \"conflict\": \"双方几乎撞面，苏敛巧妙错开时间。\", \"issueIds\": [], \"location\": \"万事阁内厅\", \"parentId\": \"1780290346047-ff511a63\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.048Z\", \"plotStage\": \"idea\", \"proseHint\": \"用眼神、茶盏摆放等细节暗示信息交易。\", \"timeLabel\": \"巳时/午时\", \"updatedAt\": \"2026-06-01T05:05:46.048Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346040-e56b2b03\"], \"storylineIds\": [\"1780290346042-16e4f667\"], \"emotionalTurn\": \"从客套到暗流涌动\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346050-16dc0deb\", \"goal\": \"第一次冲突验证苏敛的布局。\", \"level\": \"scene\", \"order\": 5, \"title\": \"情报发酵\", \"twist\": \"\", \"result\": \"两派各有死伤，苏敛得到一批灵石和法器。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"仙魔两派因情报中的“灵药”发生争斗，苏敛在旁观察，并派阿福收集战场遗物。\", \"tension\": 4, \"conflict\": \"战斗激烈，但苏敛始终未露面。\", \"issueIds\": [], \"location\": \"边境荒山\", \"parentId\": \"1780290346047-ff511a63\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.050Z\", \"plotStage\": \"idea\", \"proseHint\": \"描写远处爆炸的火光和苏敛面无表情的计算声。\", \"timeLabel\": \"深夜\", \"updatedAt\": \"2026-06-01T05:05:46.050Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346040-9c0782a6\"], \"storylineIds\": [\"1780290346042-16e4f667\"], \"emotionalTurn\": \"短暂兴奋后恢复冷静\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346051-710a750c\", \"goal\": \"引入厉寒，展现苏敛面对危机的应变。\", \"level\": \"chapter\", \"order\": 6, \"title\": \"少主寻仇\", \"twist\": \"苏敛透露厉寒的软肋（他凡间的情人墓地被魔宗监视）。\", \"result\": \"苏敛凭智谋稳住厉寒，并设计借妖盟之手将他逼入死路。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"魔宗少主厉寒因父兄死于仙魔冲突，怀疑万事阁从中挑拨，上门寻仇。\", \"tension\": 4, \"conflict\": \"厉寒武力压制，苏敛靠话语拖延。\", \"issueIds\": [], \"location\": \"万事阁\", \"parentId\": \"1780290346046-fecb8089\", \"suspense\": \"厉寒是否会掉入陷阱？\", \"createdAt\": \"2026-06-01T05:05:46.051Z\", \"plotStage\": \"idea\", \"proseHint\": \"厉寒的剑抵住苏敛的脖子，苏敛却轻笑说起他情人的往事。\", \"timeLabel\": \"次日\", \"updatedAt\": \"2026-06-01T05:05:46.051Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346038-6551a4b8\", \"1780290346040-9c0782a6\"], \"storylineIds\": [\"1780290346043-e8951958\"], \"emotionalTurn\": \"从暴怒到惊疑\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346038-6551a4b8\"}, {\"id\": \"1780290346053-f9c75ec0\", \"goal\": \"苏敛用言语扭转局面。\", \"level\": \"scene\", \"order\": 7, \"title\": \"剑下谈判\", \"twist\": \"\", \"result\": \"厉寒暂时收手，但要求证据。苏敛答应提供。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"厉寒质问苏敛，苏敛承认自己是幕后推手，但指出他的真正仇人是魔宗现任宗主（厉寒的叔叔），并提出合作。\", \"tension\": 5, \"conflict\": \"厉寒随时可能动手，苏敛保持镇定。\", \"issueIds\": [], \"location\": \"万事阁前厅\", \"parentId\": \"1780290346051-710a750c\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.053Z\", \"plotStage\": \"idea\", \"proseHint\": \"苏敛的茶杯上映出厉寒扭曲的脸。\", \"timeLabel\": \"午后\", \"updatedAt\": \"2026-06-01T05:05:46.053Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346038-6551a4b8\"], \"storylineIds\": [\"1780290346043-e8951958\"], \"emotionalTurn\": \"从杀意到犹豫\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346038-6551a4b8\"}, {\"id\": \"1780290346054-b5bbb745\", \"goal\": \"推动厉寒成为魔宗公敌。\", \"level\": \"scene\", \"order\": 8, \"title\": \"借妖设局\", \"twist\": \"妖盟中竟有厉寒旧识，差点识破。\", \"result\": \"魔宗发布追杀令，厉寒走投无路。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"苏敛暗中联络妖盟，伪造厉寒叛投妖盟的证据，并故意让魔宗截获。\", \"tension\": 4, \"conflict\": \"苏敛需同时安抚妖盟和魔宗眼线。\", \"issueIds\": [], \"location\": \"妖盟据点/魔宗议事厅\", \"parentId\": \"1780290346051-710a750c\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.054Z\", \"plotStage\": \"idea\", \"proseHint\": \"通过苏敛的视角呈现多方行动的时间差。\", \"timeLabel\": \"三日后\", \"updatedAt\": \"2026-06-01T05:05:46.054Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346039-351a97d2\", \"1780290346038-6551a4b8\"], \"storylineIds\": [\"1780290346043-e8951958\", \"1780290346042-16e4f667\"], \"emotionalTurn\": \"紧张但控制良好\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346056-f398ba48\", \"goal\": \"完成厉寒的身份转变，同时展示苏敛的冷酷。\", \"level\": \"chapter\", \"order\": 9, \"title\": \"收服死士\", \"twist\": \"苏敛并未真的挖坟，只是试探出厉寒的底线。\", \"result\": \"厉寒成为苏敛的死士，内心充满恨意但也无奈。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"厉寒被魔宗追杀重伤，向苏敛求救，苏敛逼迫他立下血誓成为死士。\", \"tension\": 5, \"conflict\": \"厉寒拒绝立誓，苏敛以他情人的遗体威胁。\", \"issueIds\": [], \"location\": \"万事阁密室\", \"parentId\": \"1780290346046-fecb8089\", \"suspense\": \"厉寒是否真心屈服？\", \"createdAt\": \"2026-06-01T05:05:46.056Z\", \"plotStage\": \"idea\", \"proseHint\": \"血誓的咒文在黑暗中闪烁，厉寒的眼泪滴落在符文上。\", \"timeLabel\": \"夜\", \"updatedAt\": \"2026-06-01T05:05:46.056Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346038-6551a4b8\"], \"storylineIds\": [\"1780290346043-e8951958\"], \"emotionalTurn\": \"从绝望到认命\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346038-6551a4b8\"}, {\"id\": \"1780290346057-4d9a69a0\", \"goal\": \"获得稳定资源，并与仙族高层建立利益捆绑。\", \"level\": \"act\", \"order\": 10, \"title\": \"仙长之谋\", \"twist\": \"\", \"result\": \"\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"仙族长老清虚欲收苏敛为徒，苏敛利用清虚的丑闻换取灵石矿脉经营权，进一步加强势力。\", \"tension\": 3, \"conflict\": \"\", \"issueIds\": [], \"location\": \"仙族清虚峰\", \"parentId\": \"1780290346044-d19a9d66\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.057Z\", \"plotStage\": \"idea\", \"proseHint\": \"仙族道场与边境的繁华对比，衬托苏敛的格格不入。\", \"timeLabel\": \"一个月后\", \"updatedAt\": \"2026-06-01T05:05:46.057Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346039-abe77d0a\"], \"storylineIds\": [\"1780290346043-ebfcf2f6\"], \"emotionalTurn\": \"\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346059-d2784510\", \"goal\": \"展现清虚的傲慢和苏敛的拒绝艺术。\", \"level\": \"chapter\", \"order\": 11, \"title\": \"登门收徒\", \"twist\": \"苏敛拿出一份清虚私通魔族的交易记录副本。\", \"result\": \"苏敛婉拒，但暗示知道清虚的秘密。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"清虚亲自来访万事阁，表示欣赏苏敛才干，愿收其为关门弟子。\", \"tension\": 4, \"conflict\": \"清虚以仙族权威施压，苏敛巧妙化解。\", \"issueIds\": [], \"location\": \"万事阁书房\", \"parentId\": \"1780290346057-4d9a69a0\", \"suspense\": \"清虚会如何反应？\", \"createdAt\": \"2026-06-01T05:05:46.059Z\", \"plotStage\": \"idea\", \"proseHint\": \"案上一盏茶，两人对话暗藏杀机，窗外暮色渐浓。\", \"timeLabel\": \"黄昏\", \"updatedAt\": \"2026-06-01T05:05:46.059Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346039-abe77d0a\", \"1780290346040-9c0782a6\"], \"storylineIds\": [\"1780290346043-ebfcf2f6\"], \"emotionalTurn\": \"从恭敬到危险的平静\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346061-586d2de2\", \"goal\": \"获得长期资源。\", \"level\": \"chapter\", \"order\": 12, \"title\": \"矿脉交换\", \"twist\": \"\", \"result\": \"签约成功，苏敛正式开矿，财力大增。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"苏敛与清虚谈判，以保守秘密为代价换取一座灵石矿脉的经营权。\", \"tension\": 3, \"conflict\": \"清虚部下得知后反对，清虚强行压制。\", \"issueIds\": [], \"location\": \"清虚峰客厅\", \"parentId\": \"1780290346057-4d9a69a0\", \"suspense\": \"清虚是否会秋后算账？\", \"createdAt\": \"2026-06-01T05:05:46.061Z\", \"plotStage\": \"idea\", \"proseHint\": \"契约上的字金光闪烁，苏敛签字时微微上扬的嘴角。\", \"timeLabel\": \"三日后\", \"updatedAt\": \"2026-06-01T05:05:46.061Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346039-abe77d0a\"], \"storylineIds\": [\"1780290346043-ebfcf2f6\"], \"emotionalTurn\": \"从紧张到志在必得\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346062-670b8bbe\", \"goal\": \"发展情感线并制造重大挫折，让苏敛付出代价。\", \"level\": \"act\", \"order\": 13, \"title\": \"妖心之劫\", \"twist\": \"\", \"result\": \"\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"妖族公主青鸾因调查边境纠纷与苏敛相识，苏敛利用她的感情获取妖盟情报，最终被揭穿，青鸾自爆妖丹毁掉万事阁。\", \"tension\": 4, \"conflict\": \"\", \"issueIds\": [], \"location\": \"万事阁/妖盟领地\", \"parentId\": \"1780290346044-d19a9d66\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.062Z\", \"plotStage\": \"idea\", \"proseHint\": \"用温暖明亮的色调描写前期甜蜜，逐渐转为阴冷。\", \"timeLabel\": \"夏末\", \"updatedAt\": \"2026-06-01T05:05:46.062Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346039-351a97d2\", \"1780290346038-6551a4b8\"], \"storylineIds\": [\"1780290346043-4f97d666\"], \"emotionalTurn\": \"\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346064-7d74949e\", \"goal\": \"建立苏敛与青鸾的情感联系。\", \"level\": \"chapter\", \"order\": 14, \"title\": \"初遇与利用\", \"twist\": \"\", \"result\": \"青鸾对苏敛产生好感，时常来访。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"青鸾伪装成普通修士调查仙魔冲突，在万事阁与苏敛偶遇，苏敛识破身份后刻意亲近。\", \"tension\": 2, \"conflict\": \"青鸾的随从怀疑苏敛，但被青鸾压下。\", \"issueIds\": [], \"location\": \"万事阁花园\", \"parentId\": \"1780290346062-670b8bbe\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.064Z\", \"plotStage\": \"idea\", \"proseHint\": \"阳光透过树叶洒在苏敛脸上，青鸾第一次心跳加速。\", \"timeLabel\": \"午后\", \"updatedAt\": \"2026-06-01T05:05:46.064Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346039-351a97d2\", \"1780290346040-9c0782a6\"], \"storylineIds\": [\"1780290346043-4f97d666\"], \"emotionalTurn\": \"从好奇到心动\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346039-351a97d2\"}, {\"id\": \"1780290346065-53a2f477\", \"goal\": \"展示苏敛的冷酷算计，同时加深青鸾的投入。\", \"level\": \"chapter\", \"order\": 15, \"title\": \"情网深陷\", \"twist\": \"\", \"result\": \"妖盟遭受损失，青鸾仍信任苏敛。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"苏敛利用青鸾的感情，套取妖盟内部情报，并借助妖盟力量打击魔宗。\", \"tension\": 3, \"conflict\": \"厉寒看出苏敛在玩弄感情，出言提醒但被苏敛无视。\", \"issueIds\": [], \"location\": \"妖盟边境营地\", \"parentId\": \"1780290346062-670b8bbe\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.065Z\", \"plotStage\": \"idea\", \"proseHint\": \"苏敛抱着受伤的青鸾时，指尖颤抖了一瞬。\", \"timeLabel\": \"数天后\", \"updatedAt\": \"2026-06-01T05:05:46.065Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346039-351a97d2\", \"1780290346038-6551a4b8\"], \"storylineIds\": [\"1780290346043-4f97d666\"], \"emotionalTurn\": \"苏敛内心微澜但压抑\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346066-741d9315\", \"goal\": \"情感与阴谋的大爆发，造成苏敛严重损失。\", \"level\": \"chapter\", \"order\": 16, \"title\": \"真相与决裂\", \"twist\": \"苏敛坦言曾对青鸾动过真心，但依然无法挽回。\", \"result\": \"万事阁半毁，苏敛重伤，青鸾撤走妖盟势力。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"青鸾发现苏敛与仙族长老的通信，得知一切都是阴谋，愤怒对峙，最终自爆妖丹。\", \"tension\": 5, \"conflict\": \"青鸾质问，苏敛默认。厉寒试图保护苏敛反被青鸾打伤。\", \"issueIds\": [], \"location\": \"万事阁主厅\", \"parentId\": \"1780290346062-670b8bbe\", \"suspense\": \"青鸾是否真的自爆？\", \"createdAt\": \"2026-06-01T05:05:46.066Z\", \"plotStage\": \"idea\", \"proseHint\": \"青鸾的眼泪坠地化出冰花，自爆时白光刺破夜空。\", \"timeLabel\": \"深夜\", \"updatedAt\": \"2026-06-01T05:05:46.066Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346039-351a97d2\", \"1780290346038-6551a4b8\", \"1780290346040-9c0782a6\"], \"storylineIds\": [\"1780290346043-4f97d666\", \"1780290346042-16e4f667\"], \"emotionalTurn\": \"从心碎到决绝\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346039-351a97d2\"}, {\"id\": \"1780290346068-8f3b2de2\", \"goal\": \"完成一个出乎意料的结局，升华主题。\", \"level\": \"act\", \"order\": 17, \"title\": \"终局之弈\", \"twist\": \"\", \"result\": \"\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"苏敛集结魔宗、妖盟残余、散修等势力，攻打正道联盟，却在胜利在望时选择放弃，让三族互耗，自己隐身幕后。\", \"tension\": 4, \"conflict\": \"\", \"issueIds\": [], \"location\": \"正道联盟总部\", \"parentId\": \"1780290346044-d19a9d66\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.068Z\", \"plotStage\": \"idea\", \"proseHint\": \"色调阴冷，风沙蔽日，营造大战前的压抑感。\", \"timeLabel\": \"秋末\", \"updatedAt\": \"2026-06-01T05:05:46.068Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346038-6551a4b8\", \"1780290346039-abe77d0a\", \"1780290346040-e56b2b03\"], \"storylineIds\": [\"1780290346042-16e4f667\"], \"emotionalTurn\": \"\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346069-e492bab0\", \"goal\": \"展示苏敛的整合能力，并为最终决战铺垫。\", \"level\": \"chapter\", \"order\": 18, \"title\": \"联军成立\", \"twist\": \"\", \"result\": \"联军形成，但各怀鬼胎。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"苏敛游说各方势力：用利益说服魔宗，用仇恨鼓动妖盟残余，用自由吸引散修，组建联军。\", \"tension\": 3, \"conflict\": \"厉寒与魔宗旧部矛盾，清虚暗中破坏。\", \"issueIds\": [], \"location\": \"多处据点\", \"parentId\": \"1780290346068-8f3b2de2\", \"suspense\": \"联军能否齐心？\", \"createdAt\": \"2026-06-01T05:05:46.069Z\", \"plotStage\": \"idea\", \"proseHint\": \"不同势力的旗帜并立，苏敛在帐篷里独自审视地图。\", \"timeLabel\": \"一周内\", \"updatedAt\": \"2026-06-01T05:05:46.069Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346038-6551a4b8\", \"1780290346039-abe77d0a\", \"1780290346040-e56b2b03\"], \"storylineIds\": [\"1780290346042-16e4f667\"], \"emotionalTurn\": \"从容但偶有疲惫\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346071-b9d8fbdf\", \"goal\": \"为战役制造紧张感。\", \"level\": \"chapter\", \"order\": 19, \"title\": \"决战前夕\", \"twist\": \"苏敛故意让清虚泄露假消息。\", \"result\": \"计划看似周密，但暗含苏敛的后手。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"苏敛部署作战计划，清虚和厉寒各行其是，云华送来正道联盟内应情报。\", \"tension\": 4, \"conflict\": \"清虚贪功私自行动暴露了联军意图。\", \"issueIds\": [], \"location\": \"联军营地\", \"parentId\": \"1780290346068-8f3b2de2\", \"suspense\": \"\", \"createdAt\": \"2026-06-01T05:05:46.071Z\", \"plotStage\": \"idea\", \"proseHint\": \"篝火映照每个人的面孔，苏敛独自在影子里微笑。\", \"timeLabel\": \"夜\", \"updatedAt\": \"2026-06-01T05:05:46.071Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346038-6551a4b8\", \"1780290346039-abe77d0a\", \"1780290346040-e56b2b03\"], \"storylineIds\": [\"1780290346042-16e4f667\", \"1780290346043-ebfcf2f6\"], \"emotionalTurn\": \"一切尽在掌控\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346072-4e98652f\", \"goal\": \"完成主题升华，留下开放结局。\", \"level\": \"chapter\", \"order\": 20, \"title\": \"放弃与余波\", \"twist\": \"苏敛告知厉寒：他的仇人（魔宗宗主）已在混战中死亡，厉寒自由了。\", \"result\": \"正道联盟元气大伤但未灭，三族进入新平衡，苏敛消失于江湖。\", \"status\": \"todo\", \"novelId\": \"1780052393947-a77672e0\", \"summary\": \"联军攻入正道联盟总部，胜利在望时苏敛突然下令撤退。他解释：消灭正道只会让魔宗一家独大，不如让三族继续争斗。联军解散，苏敛离开。\", \"tension\": 4, \"conflict\": \"厉寒和清虚反对撤退，苏敛展示更大布局：他早已安排云华在正道内部分裂权力，后续无需武力。\", \"issueIds\": [], \"location\": \"正道联盟大殿\", \"parentId\": \"1780290346068-8f3b2de2\", \"suspense\": \"苏敛下一步会去哪里？他是否会因魔血爆发而死？\", \"createdAt\": \"2026-06-01T05:05:46.072Z\", \"plotStage\": \"idea\", \"proseHint\": \"苏敛背对战场，身影渐隐在晨雾中，只留下一柄折断的羽扇。\", \"timeLabel\": \"黎明\", \"updatedAt\": \"2026-06-01T05:05:46.072Z\", \"factionIds\": [], \"characterIds\": [\"1780290346037-3ed6c0cd\", \"1780290346038-6551a4b8\", \"1780290346039-abe77d0a\", \"1780290346040-e56b2b03\"], \"storylineIds\": [\"1780290346042-16e4f667\", \"1780290346043-53fa3dfa\"], \"emotionalTurn\": \"从决战的高昂到冷静的释然\", \"foreshadowIds\": [], \"povCharacterId\": \"1780290346037-3ed6c0cd\"}], \"chapters\": [], \"factions\": [], \"categories\": [], \"characters\": [{\"id\": \"1780290346040-e56b2b03\", \"age\": \"\", \"arc\": \"从怀疑苏敛到被其智慧折服，最后陷入立场与良知的挣扎。\", \"goal\": \"维护正道秩序。\", \"name\": \"云华\", \"notes\": \"正道联盟探子；冷静机警，带一丝书卷气。；机智多疑，行事谨慎，内心正直但奉行结果正义。；自己的行动导致无辜者死亡。\", \"gender\": \"\", \"secret\": \"他曾被魔族俘虏，靠出卖同门逃生，此事成为心魔。\", \"aliases\": [], \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.040Z\", \"updatedAt\": \"2026-06-01T05:05:46.040Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1780290346040-9c0782a6\", \"age\": \"\", \"arc\": \"从一个普通掌柜成长为苏敛的得力臂助。\", \"goal\": \"过安稳日子，不想卷入纷争。\", \"name\": \"阿福\", \"notes\": \"万事阁掌柜（苏敛的助手）；朴实憨厚，偶尔会冒出金句。；忠诚老实，看似平庸实则心细如发，对苏敛绝对服从。；苏敛出事。\", \"gender\": \"\", \"secret\": \"他是苏敛早年救下的凡人，曾因胆小害死家人，发誓不再懦弱。\", \"aliases\": [], \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.040Z\", \"updatedAt\": \"2026-06-01T05:05:46.040Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1780290346039-351a97d2\", \"age\": \"\", \"arc\": \"从天真少女到心如死灰的复仇者，最后选择自我毁灭来报复。\", \"goal\": \"找到一个真心待她的伴侣。\", \"name\": \"青鸾\", \"notes\": \"妖族公主；天真清脆，带一丝娇蛮，受伤后变得冷漠低沉。；纯真直率，对爱情充满幻想，但骨子里倔强骄傲，无法容忍欺骗。；被利用后再被抛弃。\", \"gender\": \"\", \"secret\": \"她体内有妖皇封印的力量，一旦自爆可毁天灭地。\", \"aliases\": [], \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.039Z\", \"updatedAt\": \"2026-06-01T05:05:46.039Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1780290346039-abe77d0a\", \"age\": \"\", \"arc\": \"从高高在上的掌控者沦为苏敛的棋子，最终被仙族抛弃。\", \"goal\": \"成为仙族掌权者。\", \"name\": \"清虚\", \"notes\": \"仙族长老；温和慈祥，但措辞圆滑，常藏机锋。；道貌岸然，贪婪自私，善于利用规则谋取利益，对权力有极强占有欲。；丑闻曝光导致身败名裂。\", \"gender\": \"\", \"secret\": \"他曾与魔族交易，用同门性命换取突破丹药。\", \"aliases\": [], \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.038Z\", \"updatedAt\": \"2026-06-01T05:05:46.038Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1780290346038-6551a4b8\", \"age\": \"\", \"arc\": \"从仇恨的复仇者转变为苏敛的忠诚执行者，并逐渐理解苏敛的冷酷。\", \"goal\": \"恢复名誉并重掌魔宗。\", \"name\": \"厉寒\", \"notes\": \"魔宗少主/死士；暴躁直接，语气粗犷，受伤时会流露出脆弱。；冲动易怒，重情义但对背叛极度敏感，表面凶狠实则内心渴望被信任。；再次被信任的人出卖。\", \"gender\": \"\", \"secret\": \"他爱上了凡间的一位女子，但对方已死。\", \"aliases\": [], \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.038Z\", \"updatedAt\": \"2026-06-01T05:05:46.038Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}, {\"id\": \"1780290346037-3ed6c0cd\", \"age\": \"\", \"arc\": \"从纯粹利益至上逐渐认识到情感的价值，但最终选择继续独行。\", \"goal\": \"掌控天下棋局，以智谋取代修为成为最强大的力量。\", \"name\": \"苏敛\", \"notes\": \"主角；温和而略带嘲讽，话中有话，常用比喻和谜语。；表面谦和散漫，实则深沉冷酷，精于计算，习惯将所有人和事视为棋子，对长生有执念但更享受布局的快感。；被发现真心或弱点，从而被人拿捏。\", \"gender\": \"\", \"secret\": \"体内魔血随时可能爆发，且他曾在幼年亲手害死最信任的同伴。\", \"aliases\": [], \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.037Z\", \"updatedAt\": \"2026-06-01T05:05:46.037Z\", \"attributes\": [], \"categoryIds\": [], \"createdInChapterId\": null, \"firstAppearanceChapterNo\": null}], \"foreshadows\": [], \"timelineEvents\": [], \"outlineStorylines\": [{\"id\": \"1780290346042-16e4f667\", \"name\": \"万事阁棋局\", \"type\": \"main\", \"color\": \"#b45309\", \"order\": 1, \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.042Z\", \"updatedAt\": \"2026-06-01T05:05:46.042Z\", \"description\": \"苏敛以万事阁为据点，通过情报和交易操控三族势力，主线推进。\"}, {\"id\": \"1780290346043-53fa3dfa\", \"name\": \"魔血隐秘\", \"type\": \"character\", \"color\": \"#7c3aed\", \"order\": 2, \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.043Z\", \"updatedAt\": \"2026-06-01T05:05:46.043Z\", \"description\": \"苏敛人魔混血的身份带来的内在挣扎与外界威胁。\"}, {\"id\": \"1780290346043-e8951958\", \"name\": \"少主归心\", \"type\": \"subplot\", \"color\": \"#2563eb\", \"order\": 3, \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.043Z\", \"updatedAt\": \"2026-06-01T05:05:46.043Z\", \"description\": \"魔宗少主厉寒从寻仇到成为苏敛死士的转变。\"}, {\"id\": \"1780290346043-4f97d666\", \"name\": \"妖情难测\", \"type\": \"romance\", \"color\": \"#db2777\", \"order\": 4, \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.043Z\", \"updatedAt\": \"2026-06-01T05:05:46.043Z\", \"description\": \"妖族公主青鸾与苏敛的情感纠葛，以及背叛的代价。\"}, {\"id\": \"1780290346043-ebfcf2f6\", \"name\": \"仙道伪善\", \"type\": \"antagonist\", \"color\": \"#dc2626\", \"order\": 5, \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.043Z\", \"updatedAt\": \"2026-06-01T05:05:46.043Z\", \"description\": \"仙族长老清虚的贪婪与虚伪，以及苏敛如何利用其丑闻。\"}], \"characterRelations\": [{\"id\": \"1780290346042-c728ef3e\", \"note\": \"厉寒曾受魔宗指派暗杀清虚，但失败。；两人在终局中被迫合作，但互相提防。；两人在终局中被迫合作，但互相提防。\", \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.042Z\", \"updatedAt\": \"2026-06-01T05:05:46.042Z\", \"relationType\": \"敌对\", \"toCharacterId\": \"1780290346039-abe77d0a\", \"fromCharacterId\": \"1780290346038-6551a4b8\"}, {\"id\": \"1780290346042-0c0247bf\", \"note\": \"阿福对苏敛忠心耿耿，苏敛也给予他信任。；阿福在苏敛受伤时成为临时决策者，逐渐独当一面。；阿福在苏敛受伤时成为临时决策者，逐渐独当一面。\", \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.042Z\", \"updatedAt\": \"2026-06-01T05:05:46.042Z\", \"relationType\": \"主仆\", \"toCharacterId\": \"1780290346040-9c0782a6\", \"fromCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346042-a3e66b4f\", \"note\": \"苏敛察觉云华身份后，通过言语暗示和利益诱导拉拢。；两人形成秘密合作关系，云华成为苏敛在正道的暗棋。；两人形成秘密合作关系，云华成为苏敛在正道的暗棋。\", \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.042Z\", \"updatedAt\": \"2026-06-01T05:05:46.042Z\", \"relationType\": \"潜在的盟友\", \"toCharacterId\": \"1780290346040-e56b2b03\", \"fromCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346042-78123de2\", \"note\": \"云华是清虚安插在边境的眼线，负责监视苏敛。；云华逐渐对清虚的命令产生怀疑，最终倒向苏敛。；云华逐渐对清虚的命令产生怀疑，最终倒向苏敛。\", \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.042Z\", \"updatedAt\": \"2026-06-01T05:05:46.042Z\", \"relationType\": \"上下级\", \"toCharacterId\": \"1780290346040-e56b2b03\", \"fromCharacterId\": \"1780290346039-abe77d0a\"}, {\"id\": \"1780290346041-3bf29e55\", \"note\": \"厉寒曾受命追杀青鸾族人，青鸾视其为仇人。；在苏敛的调解下短暂合作，但敌意未消。；在苏敛的调解下短暂合作，但敌意未消。\", \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.041Z\", \"updatedAt\": \"2026-06-01T05:05:46.041Z\", \"relationType\": \"仇敌\", \"toCharacterId\": \"1780290346039-351a97d2\", \"fromCharacterId\": \"1780290346038-6551a4b8\"}, {\"id\": \"1780290346041-dab9f4e0\", \"note\": \"苏敛用清虚的丑闻换取灵石矿脉，清虚表面答应但暗中记恨。；清虚试图反制苏敛，但屡次被识破，最终在终局中被苏敛抛弃。；清虚试图反制苏敛，但屡次被识破，最终在终局中被苏敛抛弃。\", \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.041Z\", \"updatedAt\": \"2026-06-01T05:05:46.041Z\", \"relationType\": \"相互利用\", \"toCharacterId\": \"1780290346039-abe77d0a\", \"fromCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346041-c33b6fa0\", \"note\": \"苏敛刻意引导青鸾爱上自己以获取妖盟情报。；青鸾发现真相后自爆妖丹，两人成为死敌。；青鸾发现真相后自爆妖丹，两人成为死敌。\", \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.041Z\", \"updatedAt\": \"2026-06-01T05:05:46.041Z\", \"relationType\": \"欺骗者/被骗者\", \"toCharacterId\": \"1780290346039-351a97d2\", \"fromCharacterId\": \"1780290346037-3ed6c0cd\"}, {\"id\": \"1780290346041-78a80f69\", \"note\": \"苏敛用计迫使厉寒成为死士，厉寒内心不服但受血誓约束。；厉寒从仇恨逐渐转为复杂依赖，尝试理解苏敛的动机。；厉寒从仇恨逐渐转为复杂依赖，尝试理解苏敛的动机。\", \"novelId\": \"1780052393947-a77672e0\", \"createdAt\": \"2026-06-01T05:05:46.041Z\", \"updatedAt\": \"2026-06-01T05:05:46.041Z\", \"relationType\": \"主人/死士\", \"toCharacterId\": \"1780290346038-6551a4b8\", \"fromCharacterId\": \"1780290346037-3ed6c0cd\"}], \"characterFactionMemberships\": []}','2026-05-29 13:20:32','2026-06-01 05:05:46'),('791a8a0bf52d484aa4ca55bcd2a3e937','1779435474188-882bc56f',4,'{\"items\": [{\"id\": \"1779519132465-c418bfe3\", \"name\": \"金色鲤鱼\", \"novelId\": \"1779435474188-882bc56f\", \"ownerId\": \"1779519123417-09ddaab9\", \"summary\": \"一尾巴掌大小的金黄鲤鱼，曾被陈平安想买但钱不够，后被锦衣少年买走，疑似有异常。\", \"createdAt\": \"2026-05-23T06:52:12.465Z\", \"ownerType\": \"character\", \"updatedAt\": \"2026-05-23T06:52:12.465Z\", \"firstAppearanceChapterNo\": null}], \"outline\": [{\"id\": \"1779602839342-d6c1a406\", \"goal\": \"展示一个无厘头侦探的黑色成长史\", \"level\": \"volume\", \"order\": 1, \"title\": \"荒唐大侦探\", \"twist\": \"主角自己成为最大笑话\", \"result\": \"李默独坐办公室，迎来新客户\", \"status\": \"todo\", \"novelId\": \"1779435474188-882bc56f\", \"summary\": \"李默在网红绑架案、传销案中逐渐沉沦，最终策划大骗局失去一切。\", \"tension\": 3, \"conflict\": \"真相与闹剧的边界模糊\", \"issueIds\": [], \"location\": \"\", \"parentId\": null, \"suspense\": \"他是否还能回头？\", \"createdAt\": \"2026-05-24T06:07:19.342Z\", \"plotStage\": \"idea\", \"timeLabel\": \"现代都市\", \"updatedAt\": \"2026-05-24T06:07:19.342Z\", \"factionIds\": [], \"characterIds\": [], \"foreshadowIds\": [], \"povCharacterId\": null}, {\"id\": \"1779602839342-91667b3e\", \"goal\": \"确立李默的搞笑侦探形象，铺垫其道德转折\", \"level\": \"act\", \"order\": 2, \"title\": \"初入荒诞\", \"twist\": \"破案成功却让自己成为全网公敌\", \"result\": \"李默为洗白接受传销委托\", \"status\": \"todo\", \"novelId\": \"1779435474188-882bc56f\", \"summary\": \"李默接手网红绑架案和传销案，用无厘头方式破案，却引发众怒。；情绪：从得意到狼狈；写作提示：节奏明快，对话密集，多用网络梗和吐槽\", \"tension\": 3, \"conflict\": \"李默的玩笑方式与现实规则碰撞\", \"issueIds\": [], \"location\": \"都市\", \"parentId\": \"1779602839342-d6c1a406\", \"suspense\": \"他能否挽回形象？\", \"createdAt\": \"2026-05-24T06:07:19.342Z\", \"plotStage\": \"idea\", \"timeLabel\": \"第一周\", \"updatedAt\": \"2026-05-24T06:07:19.342Z\", \"factionIds\": [], \"characterIds\": [\"1779602839338-c9edcce1\", \"1779602839339-16d5c530\", \"1779602839339-ed081b3c\", \"177960283934